mapper.select:
SELECT  FROM t_erp_produce_job


        AND job_no like concat('%', #{jobNo}, '%')


        AND produce_plan_id = #{producePlanId}


        AND order_id = #{orderId}


        AND color_code like concat('%', #{colorCode}, '%')


        AND size_code like concat('%', #{sizeCode}, '%')


        AND current_process_id = #{currentProcessId}


        AND current_process_status = #{currentProcessStatus}


        AND outsource_id = #{outsourceId}


        AND status = #{status}


ORDER BY create_time DESC
